  ('fire-eq-eng-moex-00101', 'fire-eq-eng', 'fire-eq-eng-moex-105-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '某場所消防安全設備設置自動撒水設備，採用密閉式撒水頭，其裝置場所平時最高周圍溫度為 45℃，應 選擇何種標示溫度之撒水頭？', '["75度未滿", "75度以上121度未滿", "121度以上162度未滿", "162度以上"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "d61916da2964", "answer_pdf_sha1": "82aa81c917b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
