  ('fire-eq-eng-moex-00103', 'fire-eq-eng', 'fire-eq-eng-moex-105-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '有關建築物防火區劃之牆壁，應突出建築物外牆面X公分以上。但與其交接處之外牆面長度有Y公分以 上，且該外牆構造具有與防火區劃之牆壁同等以上防火時效者，得免突出。請問上述X、Y分別為何？', '["X=45；Y=80", "X=50；Y=80", "X=45；Y=90", "X=50；Y=90"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "d61916da2964", "answer_pdf_sha1": "82aa81c917b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "105060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "105", "exam_name": "105年大地工程技師分階段、驗船師第一次食品技師消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
